# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory backend for collaborative team
management. It supports user accounts, projects, tasks, threaded messaging
with attachments, performance dashboards, ratings, and exportable reports
(CSV / PDF).

The module is implemented with the Python standard library only and is
designed around a single shared re-entrant lock so that every sub-component
(users, projects, tasks, messages, performance, reports) observes a
consistent, serialized view of the data store under concurrent access.

Design highlights
-----------------
* One global, monotonically increasing identifier space shared by all
  entity types (ids start at 1 and are globally unique).
* Read methods return deep copies so callers can never mutate internal
  state by holding on to a returned object or list.
* Secondary indexes (tasks-by-project, tasks-by-assignee, messages-by-target)
  keep look-ups O(1)/O(k) instead of scanning the whole store.
* A pluggable ``now`` callable makes time deterministic and testable.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Set, Tuple

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Access level of a registered user."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle state of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifies the structure of a generated report."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------
def _clone(obj):
    """Return a deep copy so internal state is never exposed by reference.

    Enum members are singletons that copy to themselves, so deep copying an
    entity preserves enum identity while isolating mutable fields such as the
    ``attachments`` list on a :class:`Message`.
    """

    return copy.deepcopy(obj)


class _Store:
    """Central, lock-guarded data store shared by all components."""

    def __init__(self, now):
        self._lock = threading.RLock()
        self.now = now
        self._counter = 0

        # Primary tables keyed by id.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Uniqueness indexes.
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}

        # Secondary lookup indexes.
        self.tasks_by_project: Dict[int, Set[int]] = {}
        self.tasks_by_assignee: Dict[int, Set[int]] = {}
        self.messages_by_project: Dict[int, Set[int]] = {}
        self.messages_by_task: Dict[int, Set[int]] = {}
        self.ratings_by_ratee: Dict[int, Set[int]] = {}

    def next_id(self) -> int:
        """Allocate the next globally unique id. Caller must hold the lock."""

        self._counter += 1
        return self._counter


class _Component:
    """Base for domain components; all share one re-entrant lock."""

    def __init__(self, store: _Store):
        self._store = store
        self._lock = store._lock

    # -- time -------------------------------------------------------------
    def _now(self) -> datetime:
        return self._store.now()

    def _next_id(self) -> int:
        return self._store.next_id()

    # -- raw lookups (assume the lock is held) ----------------------------
    def _require_user_raw(self, user_id: int) -> User:
        user = self._store.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0!r} not found".format(user_id))
        return user

    def _require_project_raw(self, project_id: int) -> Project:
        project = self._store.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0!r} not found".format(project_id))
        return project

    def _require_task_raw(self, task_id: int) -> Task:
        task = self._store.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0!r} not found".format(task_id))
        return task

    def _require_message_raw(self, message_id: int) -> Message:
        message = self._store.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0!r} not found".format(message_id))
        return message


# ---------------------------------------------------------------------------
# Users
# ---------------------------------------------------------------------------
class _Users(_Component):
    @staticmethod
    def _normalize_username(username: str) -> str:
        if not isinstance(username, str):
            raise ValidationError("username must be a string")
        cleaned = username.strip()
        if not cleaned:
            raise ValidationError("username must not be empty")
        return cleaned

    @staticmethod
    def _normalize_email(email: str) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("a valid email address is required")
        return cleaned

    def register(self, username, email, role=UserRole.MEMBER) -> User:
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")
        uname = self._normalize_username(username)
        mail = self._normalize_email(email)
        with self._lock:
            if uname in self._store.username_index:
                raise DuplicateError("username {0!r} already taken".format(uname))
            if mail in self._store.email_index:
                raise DuplicateError("email {0!r} already registered".format(mail))
            user = User(
                id=self._next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self._store.users[user.id] = user
            self._store.username_index[uname] = user.id
            self._store.email_index[mail] = user.id
            return _clone(user)

    def get(self, user_id: int) -> User:
        with self._lock:
            return _clone(self._require_user_raw(user_id))

    def list(self) -> List[User]:
        with self._lock:
            return [_clone(self._store.users[i]) for i in sorted(self._store.users)]

    def update(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user_raw(user_id)

            new_username = None
            if username is not None:
                new_username = self._normalize_username(username)
                owner = self._store.username_index.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "username {0!r} already taken".format(new_username)
                    )

            new_email = None
            if email is not None:
                new_email = self._normalize_email(email)
                owner = self._store.email_index.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "email {0!r} already registered".format(new_email)
                    )

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_username is not None:
                self._store.username_index.pop(user.username, None)
                user.username = new_username
                self._store.username_index[new_username] = user_id
            if new_email is not None:
                self._store.email_index.pop(user.email, None)
                user.email = new_email
                self._store.email_index[new_email] = user_id
            if role is not None:
                user.role = role
            return _clone(user)

    def delete(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user_raw(user_id)

            for project in self._store.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project and cannot be deleted")

            for task_id in self._store.tasks_by_assignee.get(user_id, ()):
                task = self._store.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks and cannot be deleted")

            self._store.username_index.pop(user.username, None)
            self._store.email_index.pop(user.email, None)
            self._store.tasks_by_assignee.pop(user_id, None)
            del self._store.users[user_id]


# ---------------------------------------------------------------------------
# Projects
# ---------------------------------------------------------------------------
class _Projects(_Component):
    @staticmethod
    def _normalize_name(name: str) -> str:
        if not isinstance(name, str):
            raise ValidationError("project name must be a string")
        cleaned = name.strip()
        if not cleaned:
            raise ValidationError("project name must not be empty")
        return cleaned

    def create(self, name, start_date, end_date, owner_id, description="") -> Project:
        clean_name = self._normalize_name(name)
        if end_date < start_date:
            raise ValidationError("end_date must not precede start_date")
        with self._lock:
            self._require_user_raw(owner_id)
            project = Project(
                id=self._next_id(),
                name=clean_name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self._store.projects[project.id] = project
            self._store.tasks_by_project[project.id] = set()
            self._store.messages_by_project[project.id] = set()
            return _clone(project)

    def get(self, project_id: int) -> Project:
        with self._lock:
            return _clone(self._require_project_raw(project_id))

    def list(self) -> List[Project]:
        with self._lock:
            return [
                _clone(self._store.projects[i]) for i in sorted(self._store.projects)
            ]

    def update(
        self, project_id, name=None, description=None, start_date=None, end_date=None
    ) -> Project:
        with self._lock:
            project = self._require_project_raw(project_id)

            new_name = project.name
            if name is not None:
                new_name = self._normalize_name(name)

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            project.name = new_name
            if description is not None:
                project.description = description
            project.start_date = new_start
            project.end_date = new_end
            return _clone(project)

    def delete(self, project_id: int) -> None:
        with self._lock:
            self._require_project_raw(project_id)

            for task_id in list(self._store.tasks_by_project.get(project_id, ())):
                task = self._store.tasks.get(task_id)
                if task is not None and task.assignee_id is not None:
                    assignees = self._store.tasks_by_assignee.get(task.assignee_id)
                    if assignees is not None:
                        assignees.discard(task_id)
                for message_id in list(
                    self._store.messages_by_task.get(task_id, ())
                ):
                    self._store.messages.pop(message_id, None)
                self._store.messages_by_task.pop(task_id, None)
                self._store.tasks.pop(task_id, None)
            self._store.tasks_by_project.pop(project_id, None)

            for message_id in list(self._store.messages_by_project.get(project_id, ())):
                self._store.messages.pop(message_id, None)
            self._store.messages_by_project.pop(project_id, None)

            del self._store.projects[project_id]


# ---------------------------------------------------------------------------
# Tasks
# ---------------------------------------------------------------------------
class _Tasks(_Component):
    @staticmethod
    def _normalize_title(title: str) -> str:
        if not isinstance(title, str):
            raise ValidationError("task title must be a string")
        cleaned = title.strip()
        if not cleaned:
            raise ValidationError("task title must not be empty")
        return cleaned

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        old = task.assignee_id
        if old is not None:
            bucket = self._store.tasks_by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._store.tasks_by_assignee.setdefault(new_assignee_id, set()).add(
                task.id
            )

    def create(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        clean_title = self._normalize_title(title)
        with self._lock:
            project = self._require_project_raw(project_id)
            if assignee_id is not None:
                self._require_user_raw(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start_date")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self._store.tasks[task.id] = task
            self._store.tasks_by_project.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self._set_assignee(task, assignee_id)
            return _clone(task)

    def get(self, task_id: int) -> Task:
        with self._lock:
            return _clone(self._require_task_raw(task_id))

    def list_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project_raw(project_id)
            ids = sorted(self._store.tasks_by_project.get(project_id, ()))
            return [_clone(self._store.tasks[i]) for i in ids]

    def list_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            self._require_user_raw(assignee_id)
            ids = sorted(self._store.tasks_by_assignee.get(assignee_id, ()))
            return [_clone(self._store.tasks[i]) for i in ids]

    def assign(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task_raw(task_id)
            self._require_user_raw(assignee_id)
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task_raw(task_id)
            self._require_user_raw(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task_raw(task_id)
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task_raw(task_id)
            if deadline is not None:
                project = self._store.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not precede project start_date"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            task = self._require_task_raw(task_id)
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED resets timing.
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Messaging
# ---------------------------------------------------------------------------
class _Messages(_Component):
    def _build_attachments(
        self, uploader_id: int, attachments: Optional[List[Tuple[str, bytes]]]
    ) -> List[Attachment]:
        built: List[Attachment] = []
        if not attachments:
            return built
        now = self._now()
        for entry in attachments:
            filename, data = entry
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must not be empty")
            size = len(data) if data is not None else 0
            built.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=now,
                )
            )
        return built

    def post(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        has_project = project_id is not None
        has_task = task_id is not None
        if has_project == has_task:
            raise ValidationError(
                "exactly one of project_id or task_id must be provided"
            )
        text = body if isinstance(body, str) else ""
        with self._lock:
            self._require_user_raw(author_id)
            if has_project:
                self._require_project_raw(project_id)
            else:
                self._require_task_raw(task_id)
            if parent_id is not None:
                self._require_message_raw(parent_id)

            built_attachments = self._build_attachments(author_id, attachments)
            if not text.strip() and not built_attachments:
                raise ValidationError(
                    "message must have a body or at least one attachment"
                )

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._now(),
                edited_at=None,
                attachments=built_attachments,
            )
            self._store.messages[message.id] = message
            if has_project:
                self._store.messages_by_project.setdefault(project_id, set()).add(
                    message.id
                )
            else:
                self._store.messages_by_task.setdefault(task_id, set()).add(message.id)
            return _clone(message)

    def edit(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message_raw(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError(
                    "message must have a body or at least one attachment"
                )
            message.body = text
            message.edited_at = self._now()
            return _clone(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message_raw(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments to this message"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must not be empty")
            size = len(data) if data is not None else 0
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return _clone(message)

    def list_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project_raw(project_id)
            ids = sorted(self._store.messages_by_project.get(project_id, ()))
            return [_clone(self._store.messages[i]) for i in ids]

    def list_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task_raw(task_id)
            ids = sorted(self._store.messages_by_task.get(task_id, ()))
            return [_clone(self._store.messages[i]) for i in ids]

    def delete(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._require_message_raw(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            if message.project_id is not None:
                bucket = self._store.messages_by_project.get(message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = self._store.messages_by_task.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)
            del self._store.messages[message_id]


# ---------------------------------------------------------------------------
# Performance
# ---------------------------------------------------------------------------
class _Performance(_Component):
    def _assignee_tasks(self, user_id: int) -> List[Task]:
        ids = self._store.tasks_by_assignee.get(user_id, ())
        return [self._store.tasks[i] for i in ids if i in self._store.tasks]

    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if task.started_at is None or task.completed_at is None:
            return None
        return (task.completed_at - task.started_at).total_seconds()

    def completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user_raw(user_id)
            tasks = self._assignee_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user_raw(user_id)
            durations = [
                self._completion_seconds(t)
                for t in self._assignee_tasks(user_id)
                if t.status == TaskStatus.COMPLETED
            ]
            durations = [d for d in durations if d is not None]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        if not isinstance(score, int) or isinstance(score, bool):
            raise ValidationError("score must be an integer between 1 and 5")
        if score < 1 or score > 5:
            raise ValidationError("score must be between 1 and 5")
        with self._lock:
            self._require_user_raw(rater_id)
            self._require_user_raw(ratee_id)
            if task_id is not None:
                self._require_task_raw(task_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self._store.ratings[rating.id] = rating
            self._store.ratings_by_ratee.setdefault(ratee_id, set()).add(rating.id)
            return _clone(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        ids = sorted(self._store.ratings_by_ratee.get(user_id, ()))
        return [self._store.ratings[i] for i in ids if i in self._store.ratings]

    def ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._require_user_raw(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [
                    {
                        "rater_id": r.rater_id,
                        "score": r.score,
                        "feedback": r.feedback,
                        "task_id": r.task_id,
                    }
                    for r in ratings
                ],
            }

    def user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._require_user_raw(user_id)
            tasks = self._assignee_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0

            durations = [
                self._completion_seconds(t)
                for t in tasks
                if t.status == TaskStatus.COMPLETED
            ]
            durations = [d for d in durations if d is not None]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Reports
# ---------------------------------------------------------------------------
class _Reports(_Component):
    def __init__(self, store: _Store, performance: _Performance):
        super().__init__(store)
        self._performance = performance

    def _project_tasks(self, project_id: int) -> List[Task]:
        ids = self._store.tasks_by_project.get(project_id, ())
        return [self._store.tasks[i] for i in ids if i in self._store.tasks]

    def project_progress(self, project_id: int) -> dict:
        with self._lock:
            project = self._require_project_raw(project_id)
            tasks = self._project_tasks(project_id)
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0

            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.deadline < now
                and task.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "completion_rate": 0.0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
            for bucket in per_assignee.values():
                if bucket["total"]:
                    bucket["completion_rate"] = bucket["completed"] / bucket["total"]

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project.id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _performance_row(self, user_id: int, scope_task_ids: Optional[Set[int]]) -> dict:
        user = self._store.users[user_id]
        assignee_ids = self._store.tasks_by_assignee.get(user_id, set())
        if scope_task_ids is not None:
            relevant_ids = assignee_ids & scope_task_ids
        else:
            relevant_ids = set(assignee_ids)
        tasks = [self._store.tasks[i] for i in relevant_ids if i in self._store.tasks]

        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        completion_rate = completed / total if total else 0.0

        durations = []
        for task in tasks:
            if task.status == TaskStatus.COMPLETED:
                seconds = self._performance._completion_seconds(task)
                if seconds is not None:
                    durations.append(seconds)
        average_completion_time = (
            sum(durations) / len(durations) if durations else None
        )

        ratings = self._performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )

        return {
            "user_id": user_id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completion_rate,
            "average_completion_time": average_completion_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            scope_task_ids: Optional[Set[int]] = None
            relevant_user_ids: Set[int] = set()

            if project_id is not None:
                self._require_project_raw(project_id)
                scope_task_ids = set(
                    self._store.tasks_by_project.get(project_id, set())
                )
                for task_id in scope_task_ids:
                    task = self._store.tasks.get(task_id)
                    if task is not None and task.assignee_id is not None:
                        relevant_user_ids.add(task.assignee_id)
            else:
                for user_id, task_ids in self._store.tasks_by_assignee.items():
                    if task_ids and user_id in self._store.users:
                        relevant_user_ids.add(user_id)

            rows = [
                self._performance_row(uid, scope_task_ids)
                for uid in sorted(relevant_user_ids)
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance(self, user_id: int) -> dict:
        with self._lock:
            user = self._require_user_raw(user_id)
            ids = sorted(self._store.tasks_by_assignee.get(user_id, ()))
            tasks = [self._store.tasks[i] for i in ids if i in self._store.tasks]

            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            completion_rate = completed / total if total else 0.0

            durations = []
            for task in tasks:
                if task.status == TaskStatus.COMPLETED:
                    seconds = self._performance._completion_seconds(task)
                    if seconds is not None:
                        durations.append(seconds)
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._performance._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            task_rows = [
                {
                    "task_id": task.id,
                    "title": task.title,
                    "status": task.status.value,
                    "project_id": task.project_id,
                    "deadline": _format_dt(task.deadline),
                    "started_at": _format_dt(task.started_at),
                    "completed_at": _format_dt(task.completed_at),
                }
                for task in tasks
            ]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # -- export -----------------------------------------------------------
    def export(self, report, report_format) -> object:
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict produced by a report method")
        report_type = report.get("report_type")
        if report_type not in {rt.value for rt in ReportType}:
            raise ValidationError("unknown report_type: {0!r}".format(report_type))

        if report_format == ReportFormat.CSV:
            return _report_to_csv(report, report_type)
        return _report_to_pdf(report, report_type)


# ---------------------------------------------------------------------------
# Export helpers
# ---------------------------------------------------------------------------
def _format_dt(value: Optional[datetime]) -> str:
    if value is None:
        return ""
    return value.isoformat()


def _format_value(value) -> str:
    if value is None:
        return ""
    if isinstance(value, float):
        return repr(value)
    if isinstance(value, datetime):
        return value.isoformat()
    return str(value)


def _report_to_csv(report: dict, report_type: str) -> str:
    output = io.StringIO()
    writer = csv.writer(output)

    if report_type == ReportType.TEAM_PERFORMANCE.value:
        header = [
            "user_id",
            "username",
            "total_tasks",
            "completed_tasks",
            "completion_rate",
            "average_completion_time",
            "rating_count",
            "rating_average",
        ]
        writer.writerow(header)
        for row in report.get("rows", []):
            writer.writerow([_format_value(row.get(col)) for col in header])

    elif report_type == ReportType.PROJECT_PROGRESS.value:
        status_counts = report.get("status_counts", {})
        header = [
            "project_id",
            "project_name",
            "total_tasks",
            "completion_rate",
            "overdue_tasks",
        ] + ["status_" + status.value for status in TaskStatus]
        writer.writerow(header)
        row = [
            _format_value(report.get("project_id")),
            _format_value(report.get("project_name")),
            _format_value(report.get("total_tasks")),
            _format_value(report.get("completion_rate")),
            _format_value(report.get("overdue_tasks")),
        ] + [_format_value(status_counts.get(status.value, 0)) for status in TaskStatus]
        writer.writerow(row)

    else:  # INDIVIDUAL_PERFORMANCE
        summary_header = [
            "user_id",
            "username",
            "total_tasks",
            "completed_tasks",
            "completion_rate",
            "average_completion_time",
            "rating_count",
            "rating_average",
        ]
        writer.writerow(summary_header)
        writer.writerow([_format_value(report.get(col)) for col in summary_header])
        writer.writerow([])
        task_header = [
            "task_id",
            "title",
            "status",
            "project_id",
            "deadline",
            "started_at",
            "completed_at",
        ]
        writer.writerow(task_header)
        for task in report.get("tasks", []):
            writer.writerow([_format_value(task.get(col)) for col in task_header])

    return output.getvalue()


def _report_lines(report: dict, report_type: str) -> List[str]:
    lines = ["Team Collaboration Report", "Type: {0}".format(report_type), ""]

    if report_type == ReportType.TEAM_PERFORMANCE.value:
        if report.get("project_id") is not None:
            lines.append("Project scope: {0}".format(report["project_id"]))
        lines.append("Members: {0}".format(len(report.get("rows", []))))
        for row in report.get("rows", []):
            lines.append(
                "User {0} ({1}): {2}/{3} tasks complete, rating {4}".format(
                    row.get("user_id"),
                    row.get("username"),
                    row.get("completed_tasks"),
                    row.get("total_tasks"),
                    _format_value(row.get("rating_average")),
                )
            )
    elif report_type == ReportType.PROJECT_PROGRESS.value:
        lines.append(
            "Project {0} ({1})".format(
                report.get("project_id"), report.get("project_name")
            )
        )
        lines.append("Total tasks: {0}".format(report.get("total_tasks")))
        lines.append(
            "Completion rate: {0}".format(_format_value(report.get("completion_rate")))
        )
        lines.append("Overdue tasks: {0}".format(report.get("overdue_tasks")))
        for status, count in report.get("status_counts", {}).items():
            lines.append("  {0}: {1}".format(status, count))
    else:  # INDIVIDUAL_PERFORMANCE
        lines.append(
            "User {0} ({1})".format(report.get("user_id"), report.get("username"))
        )
        lines.append(
            "Completed {0}/{1} tasks".format(
                report.get("completed_tasks"), report.get("total_tasks")
            )
        )
        lines.append(
            "Average rating: {0}".format(_format_value(report.get("rating_average")))
        )
        for task in report.get("tasks", []):
            lines.append(
                "  Task {0} - {1} [{2}]".format(
                    task.get("task_id"), task.get("title"), task.get("status")
                )
            )
    return lines


def _report_to_pdf(report: dict, report_type: str) -> bytes:
    lines = _report_lines(report, report_type)
    return _build_pdf(lines)


def _pdf_escape(text: str) -> str:
    return (
        text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
    )


def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal but structurally valid single-page PDF document."""

    content_ops = ["BT", "/F1 12 Tf", "14 TL", "50 750 Td"]
    for index, line in enumerate(lines):
        safe = _pdf_escape(line)
        if index > 0:
            content_ops.append("T*")
        content_ops.append("({0}) Tj".format(safe))
    content_ops.append("ET")
    content = "\n".join(content_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
        b"<< /Length "
        + str(len(content)).encode("latin-1")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(number).encode("latin-1")
        pdf += body
        pdf += b"\nendobj\n"

    xref_offset = len(pdf)
    count = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(count).encode("latin-1")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
    pdf += (
        "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF".format(
            count, xref_offset
        ).encode("latin-1")
    )
    return bytes(pdf)


# ---------------------------------------------------------------------------
# Facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe facade over the collaboration data store.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the current
        :class:`datetime.datetime`. Defaults to :func:`datetime.datetime.now`.
        Injecting a clock makes time-dependent behaviour deterministic.
    """

    def __init__(self, now=None):
        self._store = _Store(now or datetime.now)
        self._lock = self._store._lock

        self.users = _Users(self._store)
        self.projects = _Projects(self._store)
        self.tasks = _Tasks(self._store)
        self.messages = _Messages(self._store)
        self.performance = _Performance(self._store)
        self.reports = _Reports(self._store, self.performance)

    # -- users ------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        return self.users.register(username, email, role)

    def get_user(self, user_id: int) -> User:
        return self.users.get(user_id)

    def list_users(self) -> List[User]:
        return self.users.list()

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        return self.users.update(user_id, username=username, email=email, role=role)

    def delete_user(self, user_id: int) -> None:
        return self.users.delete(user_id)

    # -- projects ---------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        return self.projects.create(name, start_date, end_date, owner_id, description)

    def get_project(self, project_id: int) -> Project:
        return self.projects.get(project_id)

    def list_projects(self) -> List[Project]:
        return self.projects.list()

    def update_project(
        self, project_id, name=None, description=None, start_date=None, end_date=None
    ) -> Project:
        return self.projects.update(
            project_id,
            name=name,
            description=description,
            start_date=start_date,
            end_date=end_date,
        )

    def delete_project(self, project_id: int) -> None:
        return self.projects.delete(project_id)

    # -- tasks ------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        return self.tasks.create(project_id, title, assignee_id, deadline)

    def get_task(self, task_id: int) -> Task:
        return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        return self.tasks.list_by_assignee(assignee_id)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        return self.tasks.assign(task_id, assignee_id)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.tasks.reassign(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        return self.tasks.unassign(task_id)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        return self.tasks.update_status(task_id, status)

    # -- messaging --------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        return self.messages.post(
            author_id,
            body,
            project_id=project_id,
            task_id=task_id,
            parent_id=parent_id,
            attachments=attachments,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        return self.messages.edit(message_id, editor_id, new_body)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        return self.messages.add_attachment(message_id, uploader_id, filename, data)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        return self.messages.list_by_project(project_id)

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        return self.messages.list_by_task(task_id)

    def delete_message(self, message_id: int, requester_id: int) -> None:
        return self.messages.delete(message_id, requester_id)

    # -- performance ------------------------------------------------------
    def get_completion_rate(self, user_id: int) -> float:
        return self.performance.completion_rate(user_id)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        return self.performance.average_completion_time(user_id)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        return self.performance.submit_rating(
            rater_id, ratee_id, score, feedback=feedback, task_id=task_id
        )

    def get_ratings_summary(self, user_id: int) -> dict:
        return self.performance.ratings_summary(user_id)

    def get_user_dashboard(self, user_id: int) -> dict:
        return self.performance.user_dashboard(user_id)

    # -- reports ----------------------------------------------------------
    def project_progress_report(self, project_id: int) -> dict:
        return self.reports.project_progress(project_id)

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        return self.reports.team_performance(project_id)

    def individual_performance_report(self, user_id: int) -> dict:
        return self.reports.individual_performance(user_id)

    def export_report(self, report, report_format) -> object:
        return self.reports.export(report, report_format)
